The following index definition example uses the
sample\_mflix.movies collection. The index definition indexes only the
`title` field as the `autocomplete` type to support search-as-you-type
queries against that field using the [autocomplete](autocomplete-ref)
operator. The index definition also specifies the following:

- Use the [standard analyzer](ref-standard-analyzer) analyzer to divide
  text values into terms based on word boundaries.

- Use the `edgeGram` tokenization strategy to index characters
  starting at the left side of the words .

- Index a minimum of `3` characters per indexed sequence.

- Index a maximum of `5` characters per indexed sequence.

- Include diacritic marks in the index and query text.

- Use the `stableTfl` [Score Details](fts-similarity-algorithms) to ensure consistent document scoring
  across all search nodes and replica set members.

```c
#include <mongoc/mongoc.h>
#include <stdlib.h>

int main (void)
{
    mongoc_client_t *client = NULL;
    mongoc_collection_t *collection = NULL;
    mongoc_database_t *database = NULL;
    bson_error_t error;
    bson_t cmd = BSON_INITIALIZER;
    bool ok = true;

    mongoc_init();

    // Connect to your Atlas deployment
    client = mongoc_client_new("<connectionString>");
    if (!client) {
        fprintf(stderr, "Failed to create a MongoDB client.\n");
        ok = false;
        goto cleanup;
    }

    // Access your database and collection
    database = mongoc_client_get_database(client, "sample_mflix");
    collection = mongoc_database_get_collection(database, "movies");

    // Specify the command and the new index
    const char *cmd_str = BSON_STR({
        "createSearchIndexes" : "movies",
        "indexes" : [ {
            "name" : "default",
            "definition" : {
              "mappings": {
                "dynamic": false,
                 "fields": {
                  "title": {
                    "type": "autocomplete",
                    "analyzer": "lucene.standard",
                    "tokenization": "edgeGram",
                    "minGrams": 3,
                    "maxGrams": 5,
                    "foldDiacritics": false,
                    "similarity": { "type": "stableTfl" }
                  }
                }
              }
            }
	    } ]
	});

    // Convert your command to BSON
    if (!bson_init_from_json(&cmd, cmd_str, -1, &error)) {
        fprintf(stderr, "Failed to parse command: %s\n", error.message);
        ok = false;
        goto cleanup;
    }

  // Create the MongoDB Search index by running the command
    if (!mongoc_collection_command_simple (collection, &cmd, NULL, NULL, &error)) {
        fprintf(stderr, "Failed to run createSearchIndexes: %s\n", error.message);
        ok = false;
        goto cleanup;
    }
    printf ("Index created!\n");

cleanup:
   mongoc_collection_destroy (collection);
   mongoc_client_destroy (client);
   mongoc_database_destroy (database);
   bson_destroy (&cmd);
   mongoc_cleanup ();
   return ok ? EXIT_SUCCESS : EXIT_FAILURE;
}
```

